// ================================================================
//  InternSync — Shared Navbar
//  ✏️  EDIT ONLY THIS SECTION to update across ALL pages:
// ================================================================
var IS_NAV_CONFIG = {
  name:       "Monisha K",
  photo:      "data:image/png;base64,",
  profileURL: "intern-profile.html",
  logoutURL:  "auth.html",
  showBack:   false,   // set true on pages that need a Back button
  backURL:    "main.html"
};
// ================================================================

(function(cfg){

  // ── Inject CSS (once) ─────────────────────────────────────
  if (!document.getElementById('is-nav-css')) {
    var s = document.createElement('style');
    s.id  = 'is-nav-css';
    s.textContent = `
      :root{
        --accent:#d9a441; --accent2:#f0c060; --bg:#1a1d0f;
        --text:#f0ede4; --muted:rgba(240,237,228,0.45);
        --teal:#2dd4bf; --red:#ff6b6b;
      }
      .is-nav{
        position:relative; z-index:20;
        background:rgba(15,18,8,.85); backdrop-filter:blur(24px);
        border-bottom:1px solid rgba(255,255,255,.07);
        padding:14px 32px; display:flex; justify-content:space-between; align-items:center;
        flex-shrink:0;
      }
      .is-nav-left{ display:flex; align-items:center; gap:14px; }
      .is-nav-right{ display:flex; align-items:center; gap:14px; }

      /* Logo */
      .is-logo{ position:relative; width:48px; height:44px; flex-shrink:0; }
      .is-logo .il{ position:absolute; top:50%; left:50%; transform:translate(-50%,-50%);
        font-family:'Georgia',serif; font-size:42px; font-weight:bold; line-height:1; user-select:none; }
      .is-logo .il-i{ color:#fff; z-index:1; }
      .is-logo .il-s{ color:transparent; z-index:2;
        background:linear-gradient(120deg,transparent 28%,var(--accent) 50%,transparent 72%);
        background-size:200% 100%; -webkit-background-clip:text; background-clip:text;
        animation:is-shimmer 3s infinite linear; }
      @keyframes is-shimmer{ from{background-position:-200% 0} to{background-position:200% 0} }

      /* Back button */
      .is-back-btn{
        display:flex; align-items:center; gap:7px;
        background:transparent; border:1.5px solid rgba(217,164,65,.5);
        color:var(--accent); padding:7px 18px; border-radius:30px;
        font-family:'Syne',sans-serif; font-size:12px; font-weight:700;
        cursor:pointer; letter-spacing:.4px;
        transition:background .25s,box-shadow .25s,border-color .25s;
      }
      .is-back-btn:hover{ background:rgba(217,164,65,.1); box-shadow:0 0 16px rgba(217,164,65,.25); }

      /* Nav name */
      .is-nav-name{ font-family:'Syne',sans-serif; font-size:14px; font-weight:600; color:var(--text); }

      /* Avatar */
      .is-avatar{
        width:36px; height:36px; border-radius:50%; overflow:hidden;
        border:2px solid rgba(217,164,65,.4); cursor:pointer; flex-shrink:0;
        transition:border-color .25s, box-shadow .25s;
      }
      .is-avatar:hover{ border-color:var(--accent); box-shadow:0 0 12px rgba(217,164,65,.35); }
      .is-avatar img{ width:100%; height:100%; object-fit:cover; object-position:center 20%; display:block; }

      /* Bell */
      .is-notif-wrap{ position:relative; }
      .is-bell-btn{
        width:36px; height:36px; border-radius:50%;
        background:rgba(255,255,255,.06); border:1px solid rgba(255,255,255,.1);
        display:flex; align-items:center; justify-content:center;
        cursor:pointer; color:var(--muted);
        transition:background .2s,border-color .2s,color .2s,transform .2s;
      }
      .is-bell-btn:hover{ background:rgba(217,164,65,.1); border-color:rgba(217,164,65,.3); color:var(--accent); transform:scale(1.08); }
      .is-bell-btn svg{ width:16px; height:16px; stroke:currentColor; }
      .is-bell-badge{
        position:absolute; top:-3px; right:-3px;
        width:16px; height:16px; border-radius:50%;
        background:var(--red); border:2px solid var(--bg);
        font-size:9px; font-weight:700; color:#fff;
        display:flex; align-items:center; justify-content:center;
        font-family:'Syne',sans-serif;
      }
      .is-bell-badge.hidden{ display:none; }

      /* Notif dropdown */
      .is-notif-dropdown{
        position:absolute; top:calc(100% + 10px); right:0;
        width:310px; background:#1c2010;
        border:1px solid rgba(217,164,65,.25); border-radius:16px;
        box-shadow:0 20px 50px rgba(0,0,0,.75);
        z-index:500; overflow:hidden;
        opacity:0; pointer-events:none;
        transform:translateY(8px) scale(.97);
        transition:opacity .22s,transform .22s;
      }
      .is-notif-dropdown.open{ opacity:1; pointer-events:auto; transform:translateY(0) scale(1); }
      .is-notif-header{ display:flex; justify-content:space-between; align-items:center; padding:14px 16px 10px; border-bottom:1px solid rgba(255,255,255,.06); }
      .is-notif-header-title{ font-family:'Syne',sans-serif; font-size:11px; font-weight:700; letter-spacing:.14em; text-transform:uppercase; color:var(--accent); }
      .is-mark-read{ font-size:11px; color:var(--muted); background:none; border:none; cursor:pointer; font-family:'DM Sans',sans-serif; transition:color .2s; padding:0; }
      .is-mark-read:hover{ color:var(--accent); }
      .is-notif-list{ max-height:280px; overflow-y:auto; }
      .is-notif-list::-webkit-scrollbar{ width:4px; }
      .is-notif-list::-webkit-scrollbar-thumb{ background:rgba(217,164,65,.2); border-radius:4px; }
      .is-notif-item{ display:flex; gap:12px; padding:12px 16px; border-bottom:1px solid rgba(255,255,255,.04); cursor:pointer; transition:background .15s; }
      .is-notif-item:last-child{ border-bottom:none; }
      .is-notif-item:hover{ background:rgba(217,164,65,.06); }
      .is-notif-item.unread{ background:rgba(217,164,65,.04); }
      .is-notif-dot{ width:7px; height:7px; border-radius:50%; background:var(--accent); flex-shrink:0; margin-top:5px; transition:opacity .3s; }
      .is-notif-item.read .is-notif-dot{ opacity:0; }
      .is-notif-body{ flex:1; min-width:0; }
      .is-notif-title{ font-size:12px; font-weight:600; color:var(--text); margin-bottom:2px; }
      .is-notif-sub{ font-size:11px; color:var(--muted); line-height:1.4; }
      .is-notif-time{ font-size:10px; color:rgba(240,237,228,.25); margin-top:4px; }
      .is-notif-empty{ padding:20px 16px; text-align:center; font-size:12px; color:var(--muted); }

      /* Logout */
      .is-btn-logout{
        padding:7px 18px; border-radius:30px;
        background:transparent; border:1.5px solid rgba(217,164,65,.4);
        color:var(--accent); font-family:'DM Sans',sans-serif;
        font-size:12px; font-weight:500; cursor:pointer; letter-spacing:.3px;
        transition:background .25s,box-shadow .25s,border-color .25s,letter-spacing .25s;
      }
      .is-btn-logout:hover{ background:rgba(217,164,65,.12); border-color:var(--accent); box-shadow:0 0 14px rgba(217,164,65,.22); letter-spacing:1px; }
    `;
    document.head.appendChild(s);
  }

  // ── Build nav HTML ────────────────────────────────────────
  var backBtn = cfg.showBack
    ? '<button class="is-back-btn" id="is-back-btn"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="15 18 9 12 15 6"/></svg>Back</button>'
    : '';

  var nav = document.createElement('nav');
  nav.className = 'is-nav';
  nav.innerHTML =
    '<div class="is-nav-left">'
      + backBtn
      + '<div class="is-logo"><span class="il il-i">I</span><span class="il il-s">S</span></div>'
    + '</div>'
    + '<div class="is-nav-right">'
      + '<span class="is-nav-name">' + cfg.name + '</span>'
      + '<div class="is-avatar" id="is-avatar" title="View Profile"><img id="is-avatar-img" alt="' + cfg.name + '" src="' + cfg.photo + '" /></div>'
      + '<div class="is-notif-wrap" id="is-notif-wrap">'
        + '<button class="is-bell-btn" id="is-bell-btn">'
          + '<svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg>'
        + '</button>'
        + '<div class="is-bell-badge hidden" id="is-bell-badge">0</div>'
        + '<div class="is-notif-dropdown" id="is-notif-dropdown">'
          + '<div class="is-notif-header"><span class="is-notif-header-title">Notifications</span><button class="is-mark-read" id="is-mark-read">Mark all read</button></div>'
          + '<div class="is-notif-list" id="is-notif-list"></div>'
        + '</div>'
      + '</div>'
      + '<button class="is-btn-logout" id="is-btn-logout">Logout</button>'
    + '</div>';

  // Insert as first child of body
  document.body.insertBefore(nav, document.body.firstChild);

  // ── Wire up events ────────────────────────────────────────
  document.getElementById('is-avatar').addEventListener('click', function(){ window.location.href = cfg.profileURL; });
  document.getElementById('is-btn-logout').addEventListener('click', function(){ window.location.href = cfg.logoutURL; });

  if (cfg.showBack) {
    document.getElementById('is-back-btn').addEventListener('click', function(){ window.location.href = cfg.backURL; });
  }

  // Bell toggle
  document.getElementById('is-bell-btn').addEventListener('click', function(e){
    e.stopPropagation();
    document.getElementById('is-notif-dropdown').classList.toggle('open');
  });
  document.addEventListener('click', function(e){
    if (!e.target.closest('#is-notif-wrap'))
      document.getElementById('is-notif-dropdown').classList.remove('open');
  });

  // Mark all read
  document.getElementById('is-mark-read').addEventListener('click', function(){
    document.querySelectorAll('.is-notif-item').forEach(function(el){ el.classList.remove('unread'); el.classList.add('read'); });
    document.getElementById('is-bell-badge').classList.add('hidden');
  });

  // ── Notification helper (call from any page) ──────────────
  window.IS_setNotifs = function(notifs) {
    var list  = document.getElementById('is-notif-list');
    var badge = document.getElementById('is-bell-badge');
    var unread = notifs.filter(function(n){ return !n.read; }).length;
    badge.textContent = unread;
    badge.classList.toggle('hidden', unread === 0);
    if (!notifs.length) { list.innerHTML = '<div class="is-notif-empty">You\'re all caught up!</div>'; return; }
    list.innerHTML = notifs.map(function(n){
      return '<div class="is-notif-item ' + (n.read ? 'read' : 'unread') + '" data-id="' + n.id + '">'
        + '<div class="is-notif-dot"></div>'
        + '<div class="is-notif-body">'
          + '<div class="is-notif-title">' + n.title + '</div>'
          + '<div class="is-notif-sub">' + n.sub + '</div>'
          + '<div class="is-notif-time">' + n.time + '</div>'
        + '</div></div>';
    }).join('');
    list.querySelectorAll('.is-notif-item').forEach(function(el){
      el.addEventListener('click', function(){
        el.classList.remove('unread'); el.classList.add('read');
        var remaining = list.querySelectorAll('.is-notif-item.unread').length;
        badge.textContent = remaining;
        badge.classList.toggle('hidden', remaining === 0);
      });
    });
  };

})(IS_NAV_CONFIG);
// ── Seed notifications ────────────────────────────────────
IS_setNotifs([
  {
    id: 1,
    title: "Onboarding task due",
    sub: "Complete your profile setup by end of day.",
    time: "5 min ago",
    read: false
  },
  {
    id: 2,
    title: "New message from Mentor",
    sub: "Your offer letter is ready to sign.",
    time: "1 hour ago",
    read: false
  },
  {
    id: 3,
    title: "Team meeting scheduled",
    sub: "Stand-up tomorrow at 10:00 AM with your mentor.",
    time: "3 hours ago",
    read: false
  },
  {
    id: 4,
    title: "New Message from Mentor",
    sub: "Meeting @7 ",
    time: "5 mins ago",
    read: false
  },
  {
    id: 5,
    title: "Payroll info needed",
    sub: "Please submit your bank details to Finance.",
    time: "2 days ago",
    read: false
  }
]);